import{_ as a,o as i,c as t,ak as o}from"./chunks/framework.D5d8W79u.js";const h=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),l={name:"overview.md"};function n(s,e,r,d,m,c){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h1><p>Embedding Atlas is a tool that provides interactive visualizations for large embeddings. It allows you to visualize, cross-filter, and search embeddings and metadata.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can use Embedding Atlas directly from this website by <a href="https://apple.github.io/embedding-atlas/app/" target="_blank" rel="noreferrer">loading your own data</a>. In this online version, Embedding Atlas will compute the embedding and projection in your browser. Your data does not leave your machine.</p></div><p>Embedding Atlas is released as two packages:</p><ul><li><p>A Python package <code>embedding-atlas</code> that provides:</p><ul><li>A <a href="./tool.html">command line utility</a> for launching Embedding Atlas from command line.</li><li>A <a href="./widget.html">Python Notebook widget</a> for using Embedding Atlas in interactive Python notebooks.</li><li>A <a href="./streamlit.html">Streamlit component</a> for using Embedding Atlas in Streamlit apps.</li><li>All of these approaches allow you to compute embeddings (with custom models) and projections.</li></ul></li><li><p>An npm package <code>embedding-atlas</code> that exposes the user interface components as API so you can use them in your own applications. Below are the exposed components:</p><ul><li><a href="./embedding-view.html">EmbeddingView</a></li><li><a href="./embedding-view-mosaic.html">EmbeddingViewMosaic</a></li><li><a href="./embedding-atlas.html">EmbeddingAtlas</a></li><li><a href="./algorithms.html">Algorithms</a></li></ul></li></ul>',5)])])}const u=a(l,[["render",n]]);export{h as __pageData,u as default};
